using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ──────────────────────────────────────────────────────────────
// Configuration
// ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI (or compatible) API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ──────────────────────────────────────────────────────────────
// Build the IChatClient via MEAI abstraction over OpenAI SDK
// ──────────────────────────────────────────────────────────────
var clientOptions = new OpenAIClientOptions();
if (!string.IsNullOrEmpty(baseUrl))
{
    clientOptions.Endpoint = new Uri(baseUrl);
}

IChatClient chatClient = new OpenAIClient(new(apiKey), clientOptions)
    .GetChatClient(modelId)
    .AsIChatClient();

// ──────────────────────────────────────────────────────────────
// Create tool instances
// ──────────────────────────────────────────────────────────────
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");
httpClient.Timeout = TimeSpan.FromSeconds(15);

var searchService = new WebSearchService(httpClient);
var notes = new ResearchNotes();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchService.SearchAsync),
    AIFunctionFactory.Create(searchService.FetchPageAsync),
    AIFunctionFactory.Create(notes.AddNote),
    AIFunctionFactory.Create(notes.GetAllNotes),
};

// ──────────────────────────────────────────────────────────────
// Create the ChatClientAgent (Microsoft.Agents.AI)
// ──────────────────────────────────────────────────────────────
const string instructions = """
    You are a research agent. Your goal is to thoroughly research the given topic using the
    tools available to you and produce a well-sourced summary.

    Follow this process:
    1. Search the web for the topic using 2-3 different, targeted queries.
    2. Fetch the most relevant web pages to get detailed content.
    3. Save each key finding as a note (include the source URL).
    4. After gathering enough information, retrieve all your notes and produce a comprehensive,
       well-structured summary that synthesizes the findings and cites sources.

    Be thorough but focused. Prefer authoritative sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
};

var runOptions = new ChatClientAgentRunOptions(chatOptions);

// ──────────────────────────────────────────────────────────────
// Run the agent with streaming output
// ──────────────────────────────────────────────────────────────
var session = await agent.CreateSessionAsync();
var userMessage = $"Research the following topic and provide a comprehensive summary: {topic}";

Console.WriteLine("Agent is working...\n");

await foreach (var update in agent.RunStreamingAsync(userMessage, session, runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// ──────────────────────────────────────────────────────────────
// Display collected research notes
// ──────────────────────────────────────────────────────────────
if (notes.Count > 0)
{
    Console.WriteLine("\n══════════════════════════════════════════");
    Console.WriteLine($"        RESEARCH NOTES ({notes.Count} saved)");
    Console.WriteLine("══════════════════════════════════════════\n");
    foreach (var note in notes.GetAllNotes())
    {
        Console.WriteLine(note);
        Console.WriteLine("---");
    }
}

// ════════════════════════════════════════════════════════════════
// Tool: Web Search — searches DuckDuckGo and returns results
// ════════════════════════════════════════════════════════════════
sealed class WebSearchService(HttpClient httpClient)
{
    [Description("Search the web for information. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await httpClient.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
            {
                return "No results found.";
            }

            var sb = new StringBuilder();
            foreach (var (title, link, snippet) in results.Take(8))
            {
                sb.AppendLine($"Title: {title}");
                sb.AppendLine($"URL: {link}");
                sb.AppendLine($"Snippet: {snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch a web page and extract its text content. Use this to read detailed content from a URL found via search.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await httpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);

            // Limit content length to avoid overwhelming the context window
            const int maxChars = 6000;
            if (text.Length > maxChars)
            {
                text = text[..maxChars] + "\n\n[Content truncated]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful content from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Match DuckDuckGo result blocks
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (int i = 0; i < links.Count; i++)
        {
            var rawUrl = links[i].Groups[1].Value;
            var title = StripTags(links[i].Groups[2].Value).Trim();
            var snippet = i < snippets.Count
                ? StripTags(snippets[i].Groups[1].Value).Trim()
                : "";

            // DuckDuckGo wraps URLs in a redirect — extract the actual URL
            var actualUrl = ExtractRedirectUrl(rawUrl);

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(actualUrl))
            {
                results.Add((title, actualUrl, snippet));
            }
        }

        return results;
    }

    private static string ExtractRedirectUrl(string ddgUrl)
    {
        // DuckDuckGo format: //duckduckgo.com/l/?uddg=<encoded_url>&...
        var match = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        if (match.Success)
        {
            return Uri.UnescapeDataString(match.Groups[1].Value);
        }

        // Fallback: if it's already a direct URL
        if (ddgUrl.StartsWith("http"))
        {
            return ddgUrl;
        }

        return ddgUrl.StartsWith("//") ? "https:" + ddgUrl : ddgUrl;
    }

    private static string StripTags(string html)
        => Regex.Replace(html, "<[^>]+>", "");

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "", RegexOptions.Singleline | RegexOptions.IgnoreCase);
        // Remove tags
        cleaned = Regex.Replace(cleaned, "<[^>]+>", " ");
        // Decode common HTML entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        cleaned = Regex.Replace(cleaned, @"\s+", " ");
        // Restore paragraph-like breaks
        cleaned = Regex.Replace(cleaned, @"(\.\s)", ".\n");
        return cleaned.Trim();
    }
}

// ════════════════════════════════════════════════════════════════
// Tool: Research Notes — stores and retrieves findings
// ════════════════════════════════════════════════════════════════
sealed class ResearchNotes
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note. Use this to record key findings during research.")]
    public string AddNote(
        [Description("A short title for this note")] string title,
        [Description("The content of the note, including relevant facts and the source URL")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully ({_notes.Count} total notes).";
    }

    [Description("Retrieve all saved research notes. Call this before writing your final summary.")]
    public IEnumerable<string> GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return ["No notes have been saved yet."];
        }

        return _notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}");
    }
}

